const { ESLint } = await import('eslint');
const eslint = new ESLint({ overrideConfigFile: 'eslint.config.mjs', ruleFilter: ({ ruleId }) => ruleId === 'complexity' });
const results = await eslint.lintFiles(['src/**/*.ts','packages/**/*.ts','scripts/**/*.mjs']);
const messages = results.flatMap((result) => result.messages.map((message) => ({ filePath: result.filePath, ...message })));
console.log(JSON.stringify({ count: messages.length, messages }, null, 2));
if (messages.length > 0) process.exit(1);
